def stuck(seq, trap):
    for item in seq:
        yield item
        if item == trap:
            while True:
                yield trap


# Testhelfer – nicht ändern
def test_stuck(lst, trap, n):
    gen = stuck(iter(lst), trap)
    result = []
    for _ in range(n):
        try:
            result.append(next(gen))
        except StopIteration:
            break
